import React from 'react'
import "./Main.css"

const Main = ({ title, slogan }) => {

    return (
        <div className="main">

            <div className="title">
                <h1>{title}</h1>
                <p>{slogan}</p>
            </div>
        </div>
    )

}

export default Main
